import React, { useState, useRef } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { Search, ShoppingCart, Menu, X, User, Heart } from 'lucide-react';

const Navbar = () => {
  const [isSearchActive, setIsSearchActive] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const searchInputRef = useRef(null);
  const navigate = useNavigate();

  const cartItems = useSelector((state) => state.cart?.items || []);
  const cartCount = cartItems.reduce((total, item) => total + item.quantity, 0);

  const categories = [
    { name: 'Living Room', sub: ['Sofas', 'TV Units', 'Coffee Tables', 'Bookshelves', 'Shoe Racks'] },
    { name: 'Bedroom', sub: ['Beds', 'Wardrobes', 'Dressers', 'Nightstands', 'Mattresses'] }
  ];

  // Handles clicking the search icon to expand, and submitting the search when active
  const handleSearchSubmit = (e) => {
    e.preventDefault();
    if (isSearchActive && searchInputRef.current?.value.trim()) {
      // Execute the search navigation when the user types something and clicks the icon
      navigate(`/products?search=${encodeURIComponent(searchInputRef.current.value)}`);
      setIsSearchActive(false);
      searchInputRef.current.value = '';
    } else if (!isSearchActive) {
      // Expand the search bar if it is closed
      setIsSearchActive(true);
      setTimeout(() => {
        searchInputRef.current?.focus();
      }, 300);
    }
  };

  const handleMouseLeave = () => {
    // Only close the search bar on mouse leave if the input is empty
    if (!searchInputRef.current?.value) {
      setIsSearchActive(false);
    }
  };

  return (
    <header className="w-full bg-white shadow-sm sticky top-0 z-50">
      {/* Top Promotional Banner */}
      <div className="w-full bg-gray-50 py-1.5 border-b border-gray-200">
        <p className="text-center text-xs md:text-sm text-gray-700">
          Free Shipping on Orders Above ₹10,000 | <span className="text-orange-500 font-semibold">Use Code: VIDEM10</span>
        </p>
      </div>

      <div className="container mx-auto px-4 py-3 relative flex items-center justify-between">

        {/* Mobile Hamburger Menu Button */}
        <button
          className="md:hidden p-1 z-20 text-gray-700 hover:text-orange-500 transition-colors"
          onClick={() => setIsMenuOpen(true)}
          aria-label="Open Menu"
        >
          <Menu size={24} />
        </button>

        {/* Brand Name (Centered on Mobile, Left on Desktop) */}
        {/* Hides the logo on mobile when search is active to prevent overlapping */}
        <Link
          to="/"
          className={`absolute left-1/2 -translate-x-1/2 md:static md:translate-x-0 z-10 flex items-center gap-2 transition-opacity duration-300 ${isSearchActive ? 'opacity-0 md:opacity-100' : 'opacity-100'}`}
        >
          <img
            src="https://i.postimg.cc/NMXqNBzW/5f3ee798-2700-4e54-a412-96ef2d12dc1a.png"
            alt="Videm's Gallery Logo"
            className="hidden md:block h-10 w-auto object-contain"
          />
          <h1 className="text-xl md:text-2xl font-bold tracking-tight whitespace-nowrap">
            <span className="text-gray-900">Videm's</span> <span className="text-orange-500">Gallery</span>
          </h1>
        </Link>

        {/* Search & Action Icons */}
        <div className="flex items-center gap-4 z-20 bg-white">

          {/* Functional Search Form */}
          <form
            onSubmit={handleSearchSubmit}
            className={`flex items-center h-10 transition-[max-width,width] duration-300 ease-in-out ${isSearchActive ? 'w-48 md:w-80' : 'w-10'}`}
            onMouseEnter={() => setIsSearchActive(true)}
            onMouseLeave={handleMouseLeave}
          >
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Search for furniture and more..."
              className={`flex-1 h-full min-w-0 bg-gray-100 text-sm text-gray-800 outline-none transition-all duration-300 rounded-l-md px-4 ${isSearchActive ? 'opacity-100' : 'opacity-0 cursor-default'}`}
              onFocus={() => setIsSearchActive(true)}
            />
            <button
              type="submit"
              className="h-10 w-10 flex-shrink-0 flex items-center justify-center bg-orange-500 text-white rounded-r-md hover:bg-orange-600 transition-colors"
              aria-label="Search"
            >
              <Search size={18} />
            </button>
          </form>

          {/* Desktop Icons */}
          <div className="hidden md:flex items-center space-x-6 flex-shrink-0">
            <Link to="/profillogin" className="text-gray-700 hover:text-orange-500 transition-colors" aria-label="Profile">
              <User size={24} />
            </Link>
            <Link to="/wishlist" className="text-gray-700 hover:text-orange-500 transition-colors" aria-label="Wishlist">
              <Heart size={24} />
            </Link>
            <Link to="/cart" className="relative text-gray-700 hover:text-orange-500 transition-colors" aria-label="Cart">
              <ShoppingCart size={24} />
              {cartCount > 0 && (
                <span className="absolute -top-2 -right-2 bg-orange-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                  {cartCount > 99 ? '99+' : cartCount}
                </span>
              )}
            </Link>
          </div>

          {/* Mobile Cart Icon (Always visible) */}
          <Link to="/cart" className="md:hidden relative p-1 text-gray-700 hover:text-orange-500 transition-colors" aria-label="Cart">
            <ShoppingCart size={24} />
            {cartCount > 0 && (
              <span className="absolute -top-2 -right-2 bg-orange-500 text-white text-[10px] font-bold h-5 w-5 rounded-full flex items-center justify-center border border-white">
                {cartCount > 99 ? '99+' : cartCount}
              </span>
            )}
          </Link>
        </div>
      </div>

      {/* Desktop Navigation Links */}
      <div className="hidden md:block w-full border-t border-gray-100 bg-white">
        <div className="container mx-auto px-4 py-3">
          <ul className="flex items-center justify-center space-x-12">
            {['LIVING ROOM', 'BEDROOM', 'DINING', 'STUDY'].map((category) => (
              <li key={category}>
                <Link to={`/products?category=${category.toLowerCase().replace(' ', '-')}`} className="text-sm font-bold text-gray-800 hover:text-orange-500 tracking-wide transition-colors">
                  {category}
                </Link>
              </li>
            ))}
          </ul>
        </div>
      </div>

      {/* Mobile Drawer */}
      {isMenuOpen && (
        <div className="fixed inset-0 bg-white z-50 md:hidden flex flex-col shadow-2xl">
          <div className="p-4 border-b border-gray-100 flex items-center justify-between">
            <button
              onClick={() => setIsMenuOpen(false)}
              className="text-gray-700 hover:text-orange-500 transition-colors"
              aria-label="Close Menu"
            >
              <X size={28} />
            </button>
            <h1 className="text-xl font-bold tracking-tight text-gray-900">
              Videm's <span className="text-orange-500">Gallery</span>
            </h1>
            <div className="flex gap-4">
              <Link to="/cart" onClick={() => setIsMenuOpen(false)} className="text-gray-700 hover:text-orange-500">
                <ShoppingCart size={24} />
              </Link>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
            {categories.map((cat) => (
              <div key={cat.name} className="mb-8">
                <h2 className="text-lg font-semibold text-gray-900 mb-4">{cat.name}</h2>
                <ul className="space-y-4 ml-4 text-gray-600">
                  {cat.sub.map((sub) => (
                    <li key={sub}>
                      {/* Clicking a category closes the drawer and navigates */}
                      <Link
                        to={`/products?category=${sub.toLowerCase().replace(' ', '-')}`}
                        onClick={() => setIsMenuOpen(false)}
                        className="block w-full hover:text-orange-500 transition-colors"
                      >
                        {sub}
                      </Link>
                    </li>
                  ))}
                </ul>
              </div>
            ))}
          </div>
        </div>
      )}
    </header>
  );
};

export default Navbar;
